import React, { useEffect } from 'react';
import zack from '../../../assets/images/Zack.png';
import * as Styled from './styles';
import useMobile from '../../../helpers/hooks/useMobile';
import { useInView } from 'react-intersection-observer';
import { DarkSubTitle } from '../../../styles/common';
import Button from '../../../components/Button';
import useTablet from '../../../helpers/hooks/useTablet';

const CEOSection = (props) => {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
	});
	const isMobile = useMobile();
    const isTablet = useTablet();

    useEffect(()=>{
        window.scrollTo(0, 0);
    },[])

    return (
        <Styled.CEOSection isTablet={isTablet} ref={ref} inView={inView} isMobile={isMobile}>
            <Styled.ImgContainer>
                <Styled.CEOSectionImg src={zack} alt='CEO'/>
            </Styled.ImgContainer>
            <Styled.MainContent>
                <DarkSubTitle>{props.title}</DarkSubTitle>
                <Styled.SubTitle>{props.subtitle}</Styled.SubTitle>
                <Styled.Link href='#contact'><Button style={{width: 'auto'}} isMobile={isMobile}>Send us CV</Button></Styled.Link>
            </Styled.MainContent>
        </Styled.CEOSection>
    );
};

export default CEOSection;