import React, { useState } from 'react';
import Button from '../../../components/Button';
import { DarkSubTitle } from '../../../styles/common';
import * as Styled from './styles';
import emailjs from '@emailjs/browser';
import Captcha from '../../../components/Captcha';
import { useInView } from 'react-intersection-observer';
import TextareaAutosize from 'react-textarea-autosize';
import useMobile from '../../../helpers/hooks/useMobile';
import useTablet from '../../../helpers/hooks/useTablet';
import Spline from '@splinetool/react-spline';

export default function CareerContactSection({setIsSplineLoaded}) {
    const { ref, inView } = useInView({
		threshold: 0,
		triggerOnce: true,
		delay: 200,
	});
    const [name, setName] = useState('');
    const [position, setPosition] = useState('');
    const [message, setMessage] = useState('');
    const [telegram, setTelegram] = useState('');
	const [captcha, setCaptcha] = useState(false);
    const [formSend, setFormSend] = useState(false);
    const [isFieldsValid, setIsFieldsValid] = useState({
        name: true,
        position: true,
        message: true,
        telegram: true,
        captcha: true,
    });
    const isMobile = useMobile();
    const isTablet = useTablet();
       
    function sendMail() {
        if (isAllFieldsValid()){

            setFormSend(true);

            const templateParams = {
                from_name: name,
                message: message,
                from_position: position,
                from_telegram: telegram,
            }

            if(Object.keys(templateParams).some(field => templateParams[field].length <= 0)) return;

            emailjs.send('service_qliuj59', 'template_czy6zdj', templateParams, 'TMOKVtJBHVYSfk3x1')
            	.then(function() {
            		setName('');
            		setPosition('');
            		setMessage('');
                    setTelegram('');
            	})
        }
    }

    function isAllFieldsValid () {
        const fields = {
            name: false,
            telegram: false,
            message: false,
            position: false,
            captcha: false,
        }

        if (name) {
            fields.name = true;
        }
        if (telegram.length > 2) {
            fields.telegram = true;
        }
        if (message.length > 14) {
            fields.message = true;
        } 
        if (position.length > 5) {
            fields.position = true;
        }
        if (captcha) {
            fields.captcha = true;
        } 

        setIsFieldsValid(fields);
        return !Object.values(fields).some(item => item === false);
    }  

    function splineToRender () {
		function onSplineLoaded () {
			setTimeout(()=>{
				setIsSplineLoaded(true);
			}, 500)
		}
	
		if (isTablet) {
			return (
				<Spline
					className='spline'
					scene='https://prod.spline.design/UNNY9mFWr7jjvIWa/scene.splinecode'
					onLoad={onSplineLoaded}
				/>
			)
		} else {
			return (
				<Spline
					className='spline'
					scene='https://prod.spline.design/2cbznMkX2Jwg4pjO/scene.splinecode'
					onLoad={onSplineLoaded}
				/>
			)
		}
	}

    return (
        <Styled.SectionContainer isMobile={isMobile} isTablet={isTablet}>
            <Styled.ContactSection id='contact'>

                <Styled.MainContent ref={ref} inView={inView} formSend={formSend}>
                    {formSend && 
                        <Styled.FormSendMessage>
                            <Styled.FormSendContent>
                                <Styled.FormSendTitle>Thank you!</Styled.FormSendTitle> 
                                <Styled.FormSendSubTitle>What’s next?</Styled.FormSendSubTitle>
                                    <Styled.FormSendListItemContainer>
                                        <Styled.FormSendMarker>01</Styled.FormSendMarker>
                                        <Styled.FormSendListItem>
                                            <Styled.FormSendListMarker>01.</Styled.FormSendListMarker> We will carefully review your professional experience to determine the best career opportunity within Jito.
                                        </Styled.FormSendListItem>
                                    </Styled.FormSendListItemContainer>
                                    <Styled.FormMarkerLine />
                                    <Styled.FormSendListItemContainer>
                                        <Styled.FormSendMarker>02</Styled.FormSendMarker>
                                        <Styled.FormSendListItem>
                                            <Styled.FormSendListMarker>02.</Styled.FormSendListMarker> The Talent Specialist will arrange a meeting to present your personal career opportunity.
                                        </Styled.FormSendListItem>
                                    </Styled.FormSendListItemContainer>
                                    <Styled.FormMarkerLine />
                                    <Styled.FormSendListItemContainer>
                                        <Styled.FormSendMarker>03</Styled.FormSendMarker>
                                        <Styled.FormSendListItem>
                                            <Styled.FormSendListMarker>03.</Styled.FormSendListMarker> We will support you from the first touch till the final job offer - we value every applicant, regardless of position.
                                        </Styled.FormSendListItem>
                                    </Styled.FormSendListItemContainer>
                            </Styled.FormSendContent>

                        </Styled.FormSendMessage>
                    }
                    <Styled.Form 
                        onSubmit={(e) => { e.preventDefault() }}
                    >
                        <DarkSubTitle>Tell us about yourself</DarkSubTitle>

                        <Styled.FieldContainer>
                            <Styled.Input className={isFieldsValid.name ? '' : 'error'} placeholder='Enter name' type='text' value={name} onChange={(e) => setName(e.target.value)} />
                            <Styled.Label className={isFieldsValid.name ? '' : 'error'}>Name*</Styled.Label>
                            <Styled.ErrorMessage style={{opacity: `${!isFieldsValid.name ? 1 : 0}`}}>This field is mandatory</Styled.ErrorMessage>
                        </Styled.FieldContainer>
                        <Styled.FieldContainer>
                            <Styled.Input className={isFieldsValid.position ? '' : 'error'} placeholder='Enter position' type='text' value={position} onChange={(e) => setPosition(e.target.value)} />
                            <Styled.Label className={isFieldsValid.position ? '' : 'error'}>Position Name*</Styled.Label>
                            <Styled.ErrorMessage style={{opacity: `${!isFieldsValid.position ? 1 : 0}`}}>Enter position</Styled.ErrorMessage>
                        </Styled.FieldContainer>
                        <Styled.FieldContainer>
                            <Styled.Input className={isFieldsValid.telegram ? '' : 'error'} placeholder='Enter telegram' type='text' value={telegram} onChange={(e) => setTelegram(e.target.value)} />
                            <Styled.Label className={isFieldsValid.telegram ? '' : 'error'}>Telegram*</Styled.Label>
                            <Styled.ErrorMessage style={{opacity: `${!isFieldsValid.telegram ? 1 : 0}`}}>Enter valid email</Styled.ErrorMessage>
                        </Styled.FieldContainer>
                        <Styled.FieldContainer>
                            <TextareaAutosize className={isFieldsValid.message ? 'textarea' : 'textarea error'} placeholder='Enter message' value={message} onChange={(e) => setMessage(e.target.value)} />
                            <Styled.Label className={isFieldsValid.message ? '' : 'error'}>CV link and cover letter</Styled.Label>
                            <Styled.ErrorMessage style={{opacity: `${!isFieldsValid.message ? 1 : 0}`}}>Minimum 15 characters</Styled.ErrorMessage>
                        </Styled.FieldContainer>
                        <Styled.CapthchaContainer>
                            <Captcha setCaptcha={setCaptcha}/>
                            <Styled.ErrorMessage style={{opacity: `${!isFieldsValid.captcha ? 1 : 0}`}} className='captcha'>Incorrect CAPTCHA</Styled.ErrorMessage>
                        </Styled.CapthchaContainer>
                        <Styled.ButtonContainer>
                            <Button isMobile={isMobile} onClick={sendMail} >Send</Button>
                        </Styled.ButtonContainer> 
                    </Styled.Form>
                </Styled.MainContent>
            </Styled.ContactSection>
            {splineToRender()}
        </Styled.SectionContainer>
  )
}
